pragma solidity ^0.8.0;

contract ArrayResize {
    uint256[] public myArray;

    function resizeArray(uint256 newSize) public {
        uint256[] memory newArray = new uint256[](newSize);

        // Copy the elements from the old array to the new array
        for (uint256 i = 0; i < newSize && i < myArray.length; i++) {
            newArray[i] = myArray[i];
        }

        // Assign the new array to the original array variable
        myArray = newArray;
    }
}
```

